/**
 * ACCESSIBILITY - Quick Checks
 */
test.describe('Portal Accessibility', () => {
  const KEY_PAGES = [
    '/portal/dashboard.html',
    '/portal/invoices.html',
    '/portal/payments.html',
    '/portal/missions.html',
  ];

  for (const pagePath of KEY_PAGES) {
    test(`${pagePath} has accessible labels`, async ({ page }) => {
      await page.goto(pagePath, { waitUntil: 'domcontentloaded', timeout: 10000 });

      // Check for role attributes
      const hasMainRole = await page.locator('[role="main"], main').count();
      const hasNavRole = await page.locator('[role="navigation"], nav').count();

      // At least one semantic element should exist
      expect(hasMainRole + hasNavRole).toBeGreaterThan(0);
    });

    test(`${pagePath} has sufficient color contrast`, async ({ page }) => {
      await page.goto(pagePath, { waitUntil: 'domcontentloaded', timeout: 10000 });

      // Basic check: page should render without errors
      const bodyVisible = await page.locator('body').isVisible();
      expect(bodyVisible).toBe(true);
    });
  }
});

/**
 * RESPONSIVE - Mobile Viewport Tests
 */
test.describe('Portal Responsive', () => {
  test('portal dashboard is responsive', async ({ page }) => {
    await page.setViewportSize({ width: 375, height: 812 }); // iPhone 12 mini
    const response = await page.goto('/portal/dashboard.html', { waitUntil: 'domcontentloaded' });
    expect(response?.status()).toBe(200);

    // Check viewport meta tag
    const viewport = await page.getAttribute('meta[name="viewport"]', 'content');
    expect(viewport).toContain('width=device-width');
  });

  test('portal invoices is responsive', async ({ page }) => {
    await page.setViewportSize({ width: 768, height: 1024 }); // iPad
    const response = await page.goto('/portal/invoices.html', { waitUntil: 'domcontentloaded' });
    expect(response?.status()).toBe(200);
  });

  test('portal payments is responsive', async ({ page }) => {
    await page.setViewportSize({ width: 390, height: 844 }); // iPhone 12/13 Pro
    const response = await page.goto('/portal/payments.html', { waitUntil: 'domcontentloaded' });
    expect(response?.status()).toBe(200);
  });
});
